import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function VideoPlayerPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const videoRef = useRef(null);
  const [video, setVideo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isAuthor, setIsAuthor] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [volume, setVolume] = useState(1);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  // Получаем текущего пользователя
  const getCurrentUser = () => {
    const token = localStorage.getItem('access');
    if (!token) return null;
    try {
      const payload = JSON.parse(atob(token.split('.')[1]));
      return payload.username;
    } catch (e) {
      return null;
    }
  };

  useEffect(() => {
    const fetchVideo = async () => {
      try {
        const response = await axios.get(`http://localhost:8000/api/videos/${id}/`);
        setVideo(response.data);
        
        const currentUser = getCurrentUser();
        if (currentUser && response.data.uploaded_by_name === currentUser) {
          setIsAuthor(true);
        }
        
        setLoading(false);
      } catch (error) {
        console.error('Ошибка:', error);
        setError('Видео не найдено');
        setLoading(false);
      }
    };
    
    fetchVideo();
  }, [id]);

  // Обработчики видео
  const handlePlayPause = () => {
    if (videoRef.current) {
      if (isPlaying) {
        videoRef.current.pause();
      } else {
        videoRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  const handleVolumeChange = (e) => {
    const newVolume = parseFloat(e.target.value);
    setVolume(newVolume);
    if (videoRef.current) {
      videoRef.current.volume = newVolume;
    }
  };

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      setCurrentTime(videoRef.current.currentTime);
    }
  };

  const handleLoadedMetadata = () => {
    if (videoRef.current) {
      setDuration(videoRef.current.duration);
    }
  };

  const handleSeek = (e) => {
    const newTime = parseFloat(e.target.value);
    setCurrentTime(newTime);
    if (videoRef.current) {
      videoRef.current.currentTime = newTime;
    }
  };

  const toggleFullscreen = () => {
    if (videoRef.current) {
      if (!isFullscreen) {
        if (videoRef.current.requestFullscreen) {
          videoRef.current.requestFullscreen();
        }
      } else {
        if (document.exitFullscreen) {
          document.exitFullscreen();
        }
      }
      setIsFullscreen(!isFullscreen);
    }
  };

  const formatTime = (time) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
  };

  const handleDelete = async () => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) {
      return;
    }
    
    const token = localStorage.getItem('access');
    if (!token) {
      alert('Сначала войдите в систему');
      navigate('/login');
      return;
    }
    
    setDeleting(true);
    try {
      await axios.delete(`http://localhost:8000/api/videos/${id}/`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      alert('Видео успешно удалено');
      navigate('/');
    } catch (error) {
      console.error('Ошибка удаления:', error);
      alert('Не удалось удалить видео');
    } finally {
      setDeleting(false);
    }
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '80vh',
        color: 'white'
      }}>
        Загрузка...
      </div>
    );
  }

  if (error || !video) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '80vh',
        color: 'white'
      }}>
        {error || 'Видео не найдено'}
      </div>
    );
  }

  const videoUrl = `http://localhost:8000/api/videos/${id}/stream/`;

  return (
    <div style={{ 
      maxWidth: 1200, 
      margin: '0 auto', 
      padding: '20px',
      backgroundColor: '#0a0a0a',
      minHeight: '100vh'
    }}>
      {/* Видео плеер */}
      <div style={{
        backgroundColor: '#000',
        borderRadius: '12px',
        overflow: 'hidden',
        boxShadow: '0 4px 20px rgba(0,0,0,0.5)'
      }}>
        <video
          ref={videoRef}
          src={videoUrl}
          style={{
            width: '100%',
            height: 'auto',
            display: 'block',
            cursor: 'pointer'
          }}
          onClick={handlePlayPause}
          onTimeUpdate={handleTimeUpdate}
          onLoadedMetadata={handleLoadedMetadata}
          onPlay={() => setIsPlaying(true)}
          onPause={() => setIsPlaying(false)}
        />
        
        {/* Кастомные контролы */}
        <div style={{
          padding: '15px',
          background: 'linear-gradient(to top, rgba(0,0,0,0.9), rgba(0,0,0,0.7))',
          color: 'white'
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px', flexWrap: 'wrap' }}>
            <button
              onClick={handlePlayPause}
              style={{
                background: 'none',
                border: 'none',
                color: 'white',
                fontSize: '20px',
                cursor: 'pointer',
                padding: '5px'
              }}
            >
              {isPlaying ? '⏸️' : '▶️'}
            </button>
            
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <span>🔊</span>
              <input
                type="range"
                min="0"
                max="1"
                step="0.01"
                value={volume}
                onChange={handleVolumeChange}
                style={{ width: '100px' }}
              />
            </div>
            
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', flex: 1 }}>
              <span>{formatTime(currentTime)}</span>
              <input
                type="range"
                min="0"
                max={duration || 0}
                value={currentTime}
                onChange={handleSeek}
                style={{ flex: 1 }}
              />
              <span>{formatTime(duration)}</span>
            </div>
            
            <button
              onClick={toggleFullscreen}
              style={{
                background: 'none',
                border: 'none',
                color: 'white',
                fontSize: '20px',
                cursor: 'pointer',
                padding: '5px'
              }}
            >
              ⛶
            </button>
          </div>
        </div>
      </div>
      
      {/* Информация о видео */}
      <div style={{ 
        marginTop: '30px',
        padding: '20px',
        backgroundColor: '#1a1a1a',
        borderRadius: '12px'
      }}>
        <div style={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'start',
          flexWrap: 'wrap',
          gap: '20px'
        }}>
          <div style={{ flex: 1 }}>
            <h1 style={{ color: 'white', margin: '0 0 10px 0', fontSize: '28px' }}>
              {video.title}
            </h1>
            <p style={{ color: '#aaa', margin: '0 0 15px 0', lineHeight: '1.6' }}>
              {video.description || 'Нет описания'}
            </p>
            <div style={{ display: 'flex', gap: '20px', color: '#888', fontSize: '14px' }}>
              <span>👤 {video.uploaded_by_name || 'Аноним'}</span>
              <span>👁️ {video.views || 0} просмотров</span>
              <span>📅 {new Date(video.created_at).toLocaleDateString()}</span>
            </div>
          </div>
          
          {isAuthor && (
            <button
              onClick={handleDelete}
              disabled={deleting}
              style={{
                backgroundColor: '#ff0000',
                color: 'white',
                border: 'none',
                padding: '12px 24px',
                borderRadius: '8px',
                cursor: deleting ? 'not-allowed' : 'pointer',
                fontSize: '16px',
                fontWeight: 'bold',
                transition: 'opacity 0.2s'
              }}
              onMouseEnter={(e) => e.target.style.opacity = '0.8'}
              onMouseLeave={(e) => e.target.style.opacity = '1'}
            >
              {deleting ? 'Удаление...' : '🗑️ Удалить видео'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

export default VideoPlayerPage;
